(function (window) {
  function $(selector) {
    if (typeof selector === 'function') {
      if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', selector);
      } else {
        selector();
      }
      return;
    }

    return document.querySelector(selector);
  }

  window.$ = $;
  window.jQuery = $;
})(window);
